    flex-direction: column;
    gap: 0.7rem;
}

/* ── Left sidebar toolbar ── */

.sideToolbar {
    width: 44px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 0.2rem;
