    background:
        radial-gradient(circle at 12% 12%, rgba(59, 95, 121, 0.3), transparent 44%),
        radial-gradient(circle at 88% 88%, rgba(76, 56, 84, 0.35), transparent 38%),
        repeating-linear-gradient(145deg, rgba(231, 230, 225, 0.05) 0 2px, transparent 2px 6px),
        linear-gradient(160deg, #141b23 0%, #0d141c 100%);
    border-color: rgba(198, 209, 220, 0.24);
    box-shadow:
        inset 0 1px 0 rgba(255, 255, 255, 0.08),
        inset 0 -24px 42px rgba(0, 0, 0, 0.44),
        0 16px 30px rgba(0, 0, 0, 0.45);
}

.isDoodleActive {
    touch-action: none;
    overscroll-behavior: contain;
}

.isDropActive {
    outline: 2px solid rgba(90, 211, 159, 0.55);
    outline-offset: -2px;
}

.stageFrame {
    position: relative;
    z-index: 1;
    width: 100%;
    flex-shrink: 0;
    border-radius: 12px;
    overflow: hidden;
    touch-action: pan-y;
}

.stage {
    border-radius: 12px;
    touch-action: none;
}

.stageEditor {
    touch-action: pan-y;
}

.isDoodleActive .stageEditor {
    touch-action: none;
}

.isDoodleActive .stageFrame {
    touch-action: none;
}

.stageHud {
    position: absolute;
    right: 0.8rem;
    bottom: 0.7rem;
    z-index: 2;
    display: inline-flex;
    align-items: center;
    gap: 0.48rem;
}

.zoomBadge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 52px;
    border-radius: 999px;
    border: 1px solid rgba(24, 28, 34, 0.18);
    padding: 0.21rem 0.52rem;
    background: rgba(255, 255, 255, 0.65);
    color: #1f2933;
    font-size: 0.68rem;
    font-weight: 700;
    letter-spacing: 0.05em;
}

.hudZoomButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border-radius: 999px;
    border: 1px solid rgba(24, 28, 34, 0.18);
    background: rgba(255, 255, 255, 0.65);
    color: #1f2933;
    font-size: 0.88rem;
    font-weight: 700;
    line-height: 1;
    cursor: pointer;
    transition: background-color 120ms ease, transform 100ms ease;
    padding: 0;
}

.hudZoomButton:active {
    transform: scale(0.9);
    background: rgba(255, 255, 255, 0.85);
}

.isDark .hudZoomButton {
    border-color: rgba(255, 255, 255, 0.2);
    background: rgba(30, 38, 48, 0.6);
    color: #e2e0da;
}

.isDark .hudZoomButton:active {
    background: rgba(40, 50, 62, 0.8);
}

.isDark .zoomBadge {
    border-color: rgba(255, 255, 255, 0.2);
    background: rgba(30, 38, 48, 0.6);
    color: #e2e0da;
}

.loaderWrapper {
    min-height: 3px;
}

.editorFooter {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.65rem;
}

.wordCount {
    color: color-mix(in srgb, var(--atelier-ink) 72%, transparent);
    font-size: 0.76rem;
}

.shareButton {
    border: 1px solid rgba(18, 24, 31, 0.18);
    border-radius: 12px;
    background: linear-gradient(120deg, #ff8a4d, #ff6b3d);
    color: #fff;
    padding: 0.45rem 0.82rem;
    font-size: 0.82rem;
    font-weight: 650;
    cursor: pointer;
    transition: transform 140ms ease, box-shadow 160ms ease;
}

.shareButton:hover {
    transform: translateY(-1px);
    box-shadow: 0 10px 20px rgba(255, 107, 61, 0.24);
}

.shareButtonDisabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
    transform: none;
}

/* ── Kept for canvas viewer toolbar (toolbarDockInCv) ── */

.toolbarDockInCv {
    position: sticky;
    left: 0;
    right: 0;
    bottom: max(0.6rem, env(safe-area-inset-bottom));
    transform: none;
    width: 100%;
    max-width: 100%;
    z-index: 40;
}

.toolbarPanel {
    pointer-events: auto;
    border-radius: 22px;
    border: 1px solid var(--dock-border);
    background: var(--dock-bg);
    backdrop-filter: blur(15px) saturate(125%);
    box-shadow:
        0 14px 34px rgba(0, 0, 0, 0.2),
        inset 0 1px 0 rgba(255, 255, 255, 0.35);
    padding: 0.58rem;
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
}

.toolbarRow {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.4rem;
}

.toolbarColumn {
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
}

.toolButton,
.secondaryButton {
    border-radius: 12px;
    border: 1px solid rgba(20, 24, 29, 0.18);
    background: rgba(255, 255, 255, 0.58);
    color: #18212a;
    padding: 0.38rem 0.66rem;
    font-size: 0.77rem;
    cursor: pointer;
    transition: border-color 150ms ease, box-shadow 170ms ease, background-color 140ms ease;
}

.secondaryButton {
    border-radius: 10px;
    padding: 0.34rem 0.58rem;
}

.toolButtonActive {
    border-color: #5ad39f;
    box-shadow: 0 0 0 1px rgba(90, 211, 159, 0.36), 0 0 16px var(--atelier-glow);
    background: rgba(255, 255, 255, 0.72);
}

.snippetComposer {
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
}

.snippetInput {
    width: 100%;
    box-sizing: border-box;
    border: 1px solid rgba(20, 24, 29, 0.2);
    border-radius: 12px;
    padding: 0.5rem 0.64rem;
    background: rgba(255, 255, 255, 0.8);
    color: #18212a;
    font-size: 0.78rem;
}

.snippetInput:focus {
    outline: none;
    border-color: #5ad39f;
    box-shadow: 0 0 0 2px rgba(90, 211, 159, 0.26);
}

.snippetActions {
    display: inline-flex;
    gap: 0.38rem;
}

.paletteWrap {
    display: flex;
    flex-direction: column;
    gap: 0.34rem;
}

.paletteGroup {
    display: flex;
    flex-direction: column;
    gap: 0.22rem;
}

.paletteLabel {
    font-size: 0.68rem;
    color: color-mix(in srgb, var(--atelier-ink) 72%, transparent);
}

.colorSwatches {
    display: inline-flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.32rem;
}

.colorSwatch {
    width: 22px;
    height: 22px;
    border-radius: 999px;
    border: 1px solid rgba(20, 24, 29, 0.2);
    cursor: pointer;
}

.colorSwatchActive {
    box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.95), 0 0 0 4px rgba(90, 211, 159, 0.58);
}

.customColorLabel {
    display: inline-flex;
    align-items: center;
    gap: 0.38rem;
    font-size: 0.68rem;
    color: color-mix(in srgb, var(--atelier-ink) 70%, transparent);
}

.colorInput {
    width: 30px;
    height: 30px;
    border: 1px solid rgba(20, 24, 29, 0.2);
    border-radius: 8px;
    background: transparent;
    padding: 0;
    cursor: pointer;
}

.sizeRange {
    width: 100%;
}

.toolHint {
    font-size: 0.68rem;
    color: color-mix(in srgb, var(--atelier-ink) 70%, transparent);
}

.selectionPanel {
    display: flex;
    flex-direction: column;
    gap: 0.46rem;
}

.styleCarousel {
    display: flex;
    flex-direction: column;
    gap: 0.42rem;
}

.fontChip {
    width: 100%;
    border-radius: 12px;
    border: 1px solid rgba(20, 24, 29, 0.2);
    background: rgba(255, 255, 255, 0.65);
    text-align: left;
    padding: 0.38rem 0.5rem;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    gap: 0.24rem;
    box-sizing: border-box;
}

.fontChipActive {
    border-color: #5ad39f;
    box-shadow: 0 0 0 1px rgba(90, 211, 159, 0.36), 0 6px 16px rgba(90, 211, 159, 0.2);
}

.fontChipLabel {
    font-size: 0.65rem;
    color: color-mix(in srgb, var(--atelier-ink) 72%, transparent);
}

.fontChipPreview {
    font-size: 0.94rem;
    color: #0f141b;
}

.aspectToggle {
    display: inline-flex;
    gap: 0.34rem;
}

.ambientLight {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 0;
    border-radius: 18px;
    background: radial-gradient(
        320px circle at var(--cursor-x, 50%) var(--cursor-y, 50%),
        rgba(255, 223, 186, 0.18),
        transparent 70%
    );
    mix-blend-mode: overlay;
    opacity: var(--cursor-opacity, 0);
    transition: opacity 0.4s ease;
}

.isDark .ambientLight {
    background: radial-gradient(
        320px circle at var(--cursor-x, 50%) var(--cursor-y, 50%),
        rgba(140, 180, 255, 0.14),
        transparent 70%
    );
    mix-blend-mode: soft-light;
}

.minimapContainer {
    position: absolute;
    left: 0.7rem;
    bottom: 0.7rem;
    z-index: 2;
    border-radius: 8px;
    border: 1px solid rgba(255, 255, 255, 0.45);
    background: rgba(247, 241, 231, 0.55);
    backdrop-filter: blur(10px) saturate(120%);
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.12);
    cursor: crosshair;
    overflow: hidden;
}

.minimapDark {
    border-color: rgba(255, 255, 255, 0.18);
    background: rgba(20, 27, 35, 0.55);
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.32);
}

.minimapViewport {
    position: absolute;
    border: 1.5px solid #5ad39f;
    background: rgba(90, 211, 159, 0.12);
    border-radius: 2px;
    cursor: grab;
    box-sizing: border-box;
}

.minimapViewport:active {
    cursor: grabbing;
}

@keyframes ambientPulse {
    0% {
        opacity: 0.5;
    }
    50% {
        opacity: 0.84;
    }
    100% {
        opacity: 0.5;
    }
}

/* ── Mobile (<=820px) ── */

@media (max-width: 820px) {
    .editorLayout {
        flex-direction: column;
    }

    .sideToolbar {
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 26;
        width: 48px;
        border-radius: 0 16px 16px 0;
        display: none;
    }

    .sideToolbar.sideToolbarOpen {
        display: flex;
    }

    .sideToolbarToggle {
        display: flex;
        align-items: center;
        justify-content: center;
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 25;
        width: 24px;
        height: 56px;
        border-radius: 0 10px 10px 0;
        border: 1px solid var(--dock-border);
        border-left: none;
        background: var(--dock-bg);
        backdrop-filter: blur(10px);
        cursor: pointer;
        color: color-mix(in srgb, var(--atelier-ink) 65%, transparent);
        font-size: 0.72rem;
        padding: 0;
        line-height: 1;
    }

    .contextPanel {
        position: fixed;
        bottom: 0;
        left: 0;
        right: 0;
        width: auto;
        max-height: 50vh;
        z-index: 26;
        border-radius: 18px 18px 0 0;
        padding: 0.65rem;
        overflow-y: auto;
    }

    .viewerRoot {
        padding-bottom: 0.9rem;
    }

    .sizeRange {
        width: 100%;
    }
}

@media (max-width: 820px) {
    .toolbarDockInCv {
        left: 0;
        right: 0;
        width: 100%;
        bottom: max(0.45rem, env(safe-area-inset-bottom));
        z-index: 121;
    }

    .toolbarPanel {
        border-radius: 18px;
        max-height: min(64vh, 520px);
        overflow: auto;
    }
}

@media (prefers-reduced-motion: reduce) {
    .stageShell::after {
        animation: none;
    }

    .toolButton,
    .secondaryButton,
    .shareButton,
    .sideToolButton {
        transition: none;
    }
}

