toolUseResult.content:
.editorRoot {
    --atelier-paper: #f2ece1;
    --atelier-paper-shadow: #d8cab2;
    --atelier-ink: #1c2127;
    --atelier-accent: #ff6b3d;
    --atelier-accent-soft: rgba(255, 107, 61, 0.2);
    --atelier-glow: rgba(111, 207, 151, 0.36);
    --dock-bg: rgba(247, 241, 231, 0.62);
    --dock-border: rgba(255, 255, 255, 0.58);
    position: relative;
    display: flex;
    flex-direction: column;
    gap: 0.7rem;
    min-height: 0;
    max-width: 100%;
    overflow: visible;
}

.viewerRoot {
    padding-bottom: 1.1rem;
}

.remixBanner {
    display: inline-flex;
    align-items: center;
    width: fit-content;
    border-radius: 999px;
    padding: 0.3rem 0.68rem;
    border: 1px solid rgba(17, 25, 40, 0.2);
    background: linear-gradient(120deg, rgba(111, 207, 151, 0.15), rgba(254, 202, 87, 0.16));
    color: #2f3e46;
    font-size: 0.72rem;
    letter-spacing: 0.01em;
}

/* ── New layout wrappers ── */

.editorLayout {
    display: flex;
    flex-direction: row;
    gap: 0.55rem;
    flex: 1;
    min-height: 0;
}

.canvasColumn {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    gap: 0.7rem;
}

/* ── Left sidebar toolbar ── */

.sideToolbar {
    width: 44px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 0.2rem;
    border-radius: 16px;
    border: 1px solid var(--dock-border);
    background: var(--dock-bg);
    backdrop-filter: blur(15px) saturate(125%);
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.12),
        inset 0 1px 0 rgba(255, 255, 255, 0.35);
    align-self: flex-start;
}

.sideToolButton {
    width: 36px;
    height: 36px;
    border-radius: 10px;
    border: 1px solid rgba(20, 24, 29, 0.14);
    background: rgba(255, 255, 255, 0.45);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.82rem;
    color: #18212a;
    transition: border-color 150ms ease, box-shadow 170ms ease, background-color 140ms ease;
    padding: 0;
    line-height: 1;
}

.sideToolButton:hover {
    background: rgba(255, 255, 255, 0.7);
}

.sideToolButton.toolButtonActive {
    border-color: #5ad39f;
    box-shadow: 0 0 0 1px rgba(90, 211, 159, 0.36), 0 0 16px var(--atelier-glow);
    background: rgba(255, 255, 255, 0.72);
}

.sideToolSeparator {
    width: 26px;
    height: 1px;
    background: rgba(20, 24, 29, 0.12);
    margin: 0.2rem 0;
}

/* ── Right context panel ── */

.contextPanel {
    width: 260px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.6rem;
    border-radius: 16px;
    border: 1px solid var(--dock-border);
    background: var(--dock-bg);
    backdrop-filter: blur(15px) saturate(125%);
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.12),
        inset 0 1px 0 rgba(255, 255, 255, 0.35);
    overflow-y: auto;
    max-height: fit-content;
    align-self: flex-start;
}

.contextPanelHeader {
    font-size: 0.7rem;
    font-weight: 650;
    color: color-mix(in srgb, var(--atelier-ink) 72%, transparent);
    padding: 0 0.1rem;
}

/* ── Mobile sidebar toggle ── */

.sideToolbarToggle {
    display: none;
}

/* ── Stage shell ── */

.stageShell {
    position: relative;
    width: 100%;
    max-width: 100%;
    box-sizing: border-box;
    border-radius: 18px;
    padding: 0 clamp(0.45rem, 0.9vw, 0.85rem);
    flex-shrink: 0;
    overflow: hidden;
    border: 1px solid rgba(62, 52, 41, 0.25);
    background:
        radial-gradient(circle at 12% 12%, rgba(255, 243, 219, 0.55), transparent 40%),
        radial-gradient(circle at 88% 88%, rgba(255, 165, 130, 0.2), transparent 35%),
        repeating-linear-gradient(145deg, rgba(106, 88, 72, 0.04) 0 2px, transparent 2px 6px),
        linear-gradient(160deg, #f2ece1 0%, #e7ddcd 100%);
    box-shadow:
        inset 0 1px 0 rgba(255, 255, 255, 0.45),
        inset 0 -24px 40px rgba(69, 54, 39, 0.12),
        0 16px 30px rgba(32, 26, 22, 0.16);
}

.stageShell::before {
    content: "";
    position: absolute;
    inset: 0;
    background-image:
        radial-gradient(rgba(19, 12, 7, 0.11) 0.55px, transparent 0.7px),
        radial-gradient(rgba(255, 255, 255, 0.28) 0.8px, transparent 1px);
    background-size: 5px 5px, 7px 7px;
    opacity: 0.18;
    pointer-events: none;
}

.stageShell::after {
    content: "";
    position: absolute;
    inset: 0;
    background:
        radial-gradient(circle at 0 0, rgba(255, 191, 105, 0.2), transparent 38%),
        radial-gradient(circle at 100% 100%, rgba(111, 207, 151, 0.2), transparent 38%),
        radial-gradient(circle at 100% 0, rgba(255, 106, 74, 0.14), transparent 35%);
    mix-blend-mode: screen;
    animation: ambientPulse 7.5s ease-in-out infinite;
    pointer-events: none;
}

.isDark {
    --atelier-paper: #11161c;
    --atelier-paper-shadow: #0a0f14;
    --atelier-ink: #f2efe8;
    --dock-bg: rgba(28, 35, 44, 0.64);
    --dock-border: rgba(255, 255, 255, 0.2);
    background:
        radial-gradient(circle at 12% 12%, rgba(59, 95, 121, 0.3), transparent 44%),
        radial-gradient(circle at 88% 88%, rgba(76, 56, 84, 0.35), transparent 38%),
        repeating-linear-gradient(145deg, rgba(231, 230, 225, 0.05) 0 2px, transparent 2px 6px),
        linear-gradient(160deg, #141b23 0%, #0d141c 100%);
    border-color: rgba(198, 209, 220, 0.24);
    box-shadow:
        inset 0 1px 0 rgba(255, 255, 255, 0.08),
        inset 0 -24px 42px rgba(0, 0, 0, 0.44),
        0 16px 30px rgba(0, 0, 0, 0.45);
}

.isDoodleActive {
    touch-action: none;
    overscroll-behavior: contain;
}

.isDropActive {
    outline: 2px solid rgba(90, 211, 159, 0.55);
    outline-offset: -2px;
}

.stageFrame {
    position: relative;
    z-index: 1;
    width: 100%;
    flex-shrink: 0;
    border-radius: 12px;
    overflow: hidden;
    touch-action: pan-y;
}

.stage {
    border-radius: 12px;
    touch-action: none;
}

.stageEditor {
    touch-action: pan-y;
}

.isDoodleActive .stageEditor {
    touch-action: none;
}

.isDoodleActive .stageFrame {
    touch-action: none;
}

.stageHud {
    position: absolute;
    right: 0.8rem;
    bottom: 0.7rem;
    z-index: 2;
    display: inline-flex;
    align-items: center;
    gap: 0.48rem;
}

.zoomBadge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 52px;
    border-radius: 999px;
    border: 1px solid rgba(24, 28, 34, 0.18);
    padding: 0.21rem 0.52rem;
    background: rgba(255, 255, 255, 0.65);
    color: #1f2933;
    font-size: 0.68rem;
    font-weight: 700;
    letter-spacing: 0.05em;
}

.hudZoomButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border-radius: 999px;
    border: 1px solid rgba(24, 28, 34, 0.18);
    background: rgba(255, 255, 255, 0.65);
    color: #1f2933;
    font-size: 0.88rem;
    font-weight: 700;
    line-height: 1;
    cursor: pointer;
    transition: background-color 120ms ease, transform 100ms ease;
    padding: 0;
}

.hudZoomButton:active {
    transform: scale(0.9);
    background: rgba(255, 255, 255, 0.85);
