/* ── Mobile (<=820px) ── */

@media (max-width: 820px) {
    .editorLayout {
        flex-direction: column;
    }

    .sideToolbar {
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 26;
        width: 48px;
        border-radius: 0 16px 16px 0;
        display: none;
    }

    .sideToolbar.sideToolbarOpen {
        display: flex;
    }

    .sideToolbarToggle {
        display: flex;
        align-items: center;
        justify-content: center;
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 25;
        width: 24px;
        height: 56px;
        border-radius: 0 10px 10px 0;
        border: 1px solid var(--dock-border);
        border-left: none;
        background: var(--dock-bg);
        backdrop-filter: blur(10px);
        cursor: pointer;
        color: color-mix(in srgb, var(--atelier-ink) 65%, transparent);
        font-size: 0.72rem;
        padding: 0;
        line-height: 1;
    }

    .contextPanel {
        position: fixed;
        bottom: 0;
        left: 0;
        right: 0;
        width: auto;
        max-height: 50vh;
        z-index: 26;
        border-radius: 18px 18px 0 0;
        padding: 0.65rem;
        overflow-y: auto;
    }

    .viewerRoot {
        padding-bottom: 0.9rem;
    }

    .sizeRange {
        width: 100%;
    }
}

@media (max-width: 820px) {
    .toolbarDockInCv {
        left: 0;
        right: 0;
        width: 100%;
        bottom: max(0.45rem, env(safe-area-inset-bottom));
        z-index: 121;
    }

    .toolbarPanel {
        border-radius: 18px;
        max-height: min(64vh, 520px);
        overflow: auto;
    }
}

@media (prefers-reduced-motion: reduce) {
    .stageShell::after {
        animation: none;
    }

    .toolButton,
    .secondaryButton,
    .shareButton,
    .sideToolButton {
        transition: none;
    }
}

