                                                verticalAlign="middle"
                                                padding={8}
                                                wrap="word"
                                                draggable={canEditObjects}
                                                rotation={snippet.rotation || 0}
                                                scaleX={baseScaleX * liftMultiplier}
                                                scaleY={liftMultiplier}
                                                stroke={isSelected ? "#68d391" : "transparent"}
                                                strokeWidth={isSelected ? 1.2 : 0}
