                    <div className="freedom-wall-loading">Loading wall...</div>
                ) : (
                    <Stage
                        ref={stageRef}
                        width={stageWidth}
                        height={stageHeight}
                        pixelRatio={window.devicePixelRatio || 1}
                        scaleX={stageScale}
                        scaleY={stageScale}
                        x={stagePosition.x}
                        y={stagePosition.y}
                        onMouseDown={handleStagePointerDown}
                        onTouchStart={handleStagePointerDown}
                        onMouseMove={handleStagePointerMove}
                        onTouchMove={handleStagePointerMove}
                        onMouseUp={handleStagePointerUp}
                        onTouchEnd={handleStagePointerUp}
                        onMouseLeave={() => { handleStagePointerUp(); handleCursorLeave(); }}
                        onWheel={handleWheel}
                    >
                        <Layer listening={false}>
                            <Rect width={stageWidth} height={stageHeight} fill="#3a3836" />
                            <Rect width={stageWidth} height={stageHeight} fill="rgba(80, 75, 68, 0.12)" />
                            {Array.from({length: Math.floor(stageWidth / GRID_SIZE) + 1}).map((_, index) => (
                                <Line
                                    key={`fw-grid-v-${index}`}
                                    points={[index * GRID_SIZE, 0, index * GRID_SIZE, stageHeight]}
                                    stroke="rgba(200, 195, 185, 0.04)"
                                    strokeWidth={1}
                                />
                            ))}
                            {Array.from({length: Math.floor(stageHeight / GRID_SIZE) + 1}).map((_, index) => (
                                <Line
                                    key={`fw-grid-h-${index}`}
                                    points={[0, index * GRID_SIZE, stageWidth, index * GRID_SIZE]}
                                    stroke="rgba(200, 195, 185, 0.04)"
                                    strokeWidth={1}
                                />
                            ))}
                        </Layer>

                        <Layer>
                            {wallItemNodes}

                            {!isTimeCapsuleMode && draftSticker && (
                                <StickerNode
                                    item={{payload: draftSticker}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftSticker((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {!isTimeCapsuleMode && draftStamp && (
                                <StampNode
                                    item={{payload: draftStamp}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftStamp((prev) => ({
