                    </button>
                    {isTimeCapsuleMode && (
                        <span className="fw-label">Viewing previous week (read-only)</span>
                    )}
                    {!isTimeCapsuleMode && !isWeeksLoading && !previousWeek?.id && (
                        <span className="fw-label">Time Capsule unavailable</span>
