                                    <button
                                        key={font.name}
                                        type="button"
                                        className={`fw-font-chip ${draftNote.fontFamily === font.name ? "is-active" : ""}`}
                                        style={{ fontFamily: font.name }}
                                        onClick={() => setDraftNote((prev) => ({...prev, fontFamily: font.name}))}
