                                        {font.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="fw-draft-note-row">
                            <label>Style</label>
                            <select value={draftNote.fontStyle} onChange={(e) => setDraftNote((prev) => ({...prev, fontStyle: e.target.value}))}>
